rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // =====================================================
    // HELPER FUNCTIONS
    // =====================================================

    function isSignedIn() {
      return request.auth != null;
    }

    function getUserData() {
      return get(/databases/$(database)/documents/users/$(request.auth.uid)).data;
    }

    function getUserRole() {
      return getUserData().role;
    }

    function hasRole(role) {
      return isSignedIn() && getUserRole() == role;
    }

    function isSuperAdmin() {
      return hasRole('SUPER_ADMIN');
    }

    function isSuperAdminOrAdmin() {
      return hasRole('SUPER_ADMIN') || hasRole('ADMIN');
    }

    function isOwner(resource) {
      return isSignedIn() && resource.data.requesterId == request.auth.uid;
    }

    // =====================================================
    // PRF PREPARER CHECK
    // Allows PRF preparer to refile rejected PRFs
    // =====================================================

    function isPrfPreparer(resource) {
      return isSignedIn() && 
        resource.data.prfDetails != null && 
        resource.data.prfDetails.preparedBy == request.auth.uid;
    }

    // =====================================================
    // PERMISSION-BASED ACCESS CONTROL
    // Reads permissions from config/permissions document
    // =====================================================

    function getPermissionsDoc() {
      return get(/databases/$(database)/documents/config/permissions).data;
    }

    function hasPermission(permission) {
      // Super Admin always has all permissions, otherwise check permissions doc
      let permDoc = getPermissionsDoc();
      let userRole = getUserRole();

      return isSuperAdmin() || (
        permDoc.permissions != null && 
        permDoc.permissions[userRole] != null &&
        permDoc.permissions[userRole].hasAny([permission])
      );
    }

    // =====================================================
    // BUSINESS UNIT FUNCTIONS
    // =====================================================

    function getResourceBU(resource) {
      // Use get() with a default value to avoid ternary operators that 
      // confuse the Firestore static query analyzer.
      return resource.data.get('businessUnitId', resource.data.get('businessId', null));
    }

    function belongsToSameBU(resource) {
      let userData = getUserData();
      let resourceBuId = getResourceBU(resource);

      return isSuperAdminOrAdmin() ||
        (resourceBuId != null && (
          userData.businessId == resourceBuId ||
          (userData.businessUnitIds != null && 
           userData.businessUnitIds.hasAny([resourceBuId]))
        ));
    }

    function canReadRequisition(resource) {
      return isSuperAdminOrAdmin() ||
        hasPermission('procurement:burf:view:all') ||
        hasPermission('finance:bank_recon:enrich') ||
        resource.data.requesterId == request.auth.uid ||
        belongsToSameBU(resource);
    }

    // =====================================================
    // TIMESTAMP VALIDATION
    // Ensures timestamps are server-generated, not client-spoofed
    // =====================================================

    function hasServerTimestamp(data, field) {
      // Check if the field is a timestamp type (server timestamps are of type timestamp)
      return field in data && data[field] is timestamp;
    }

    function hasValidCreateTimestamps(data) {
      // For creates, we require server timestamps on critical audit fields
      // Note: dateCreated can be a date string for display purposes
      // but timestamp field must be a server timestamp for audit integrity
      return !('timestamp' in data) || data.timestamp is timestamp;
    }

    // =====================================================
    // DATA VALIDATION FUNCTIONS (Issue #5)
    // =====================================================

    // Valid requisition statuses
    function isValidStatus(status) {
      return status in [
        'DRAFT',
        'BURF_PENDING_MANAGER',
        'BURF_PENDING_CIC',
        'READY_FOR_PRF',
        'PRF_PENDING_MANAGER',
        // 8-Stage PRF Workflow Statuses
        'PENDING_GM_PRF_APPROVAL',
        'PENDING_FINANCE_HEAD_BR_APPROVAL',
        'PENDING_GM_BR_APPROVAL',
        'PENDING_BOD_APPROVAL',
        'FOR_CHECK_PREPARATION',
        'PENDING_CHECK_AUTH_BOD',
        'FOR_FUND_RELEASE',
        // Legacy statuses
        'PENDING_CFO_APPROVAL',
        'BURF_PARTIALLY_PROCESSED',
        // Post-approval statuses
        'APPROVED_FOR_PAYMENT',
        'FUNDS_RELEASED',
        'LIQUIDATION_FILED',
        'LIQUIDATION_REJECTED',
        'AUDITED_CLEARED',
        'REJECTED',
        'CANCELLED',
        'BURF_COMPLETED'
      ];
    }

    // Validate required fields for requisition creation
    function hasRequiredRequisitionFields(data) {
      return data.keys().hasAll(['requesterId', 'businessId', 'items', 'status', 'dateCreated']) &&
        data.requesterId is string &&
        data.businessId is string &&
        data.items is list &&
        data.status is string &&
        isValidStatus(data.status);
    }

    // Validate items array has required structure
    // Added upper limit to prevent DoS via excessively large documents (Firestore limit: 1MB)
    function hasValidItems(items) {
      return items.size() > 0 && items.size() <= 500;
    }

    // =====================================================
    // TEXT FIELD LENGTH VALIDATION
    // Prevents excessively long strings that could cause display issues or DoS
    // =====================================================

    function isValidStringLength(value, maxLength) {
      return value is string && value.size() <= maxLength;
    }

    // Validate text fields have reasonable lengths
    function hasValidTextFields(data) {
      // Description: max 500 chars
      let validDesc = !('description' in data) || 
                      data.description == null || 
                      isValidStringLength(data.description, 500);
      // Remarks: max 500 chars  
      let validRemarks = !('remarks' in data) || 
                         data.remarks == null || 
                         isValidStringLength(data.remarks, 500);
      return validDesc && validRemarks;
    }

    // =====================================================
    // WORKFLOW UPDATE FIELD VALIDATION
    // Ensures workflow actions only modify allowed fields
    // Blocks changes to sensitive fields like items, amounts, etc.
    // =====================================================

    function isValidWorkflowUpdate() {
      // Get the set of fields that changed
      let affectedKeys = request.resource.data.diff(resource.data).affectedKeys();

      // These are the ONLY fields workflow actions are allowed to modify
      // Be permissive - allow any reasonable workflow-related field
      let allowedFields = [
        'status',
        'history', 
        'updatedAt',
        'lastModified',
        'lastModifiedBy',
        'lastActionIndex',
        'approvals',
        'rejectionReason',
        'rejectedAt',
        'rejectedBy',
        'cancelledAt',
        'cancelledBy',
        'currentApproverId',
        'rejectedAtStage',
        'budgetStatus'
      ].toSet();

      return affectedKeys.hasOnly(allowedFields);
    }

    // Check Preparation update validation (Bank Reference Entry)
    // Allows bankRefNumber/bankRefLink (new) and chequeNumber/chequeImageUrl (legacy) in addition to workflow fields
    function isValidCheckPrepUpdate() {
      let affectedKeys = request.resource.data.diff(resource.data).affectedKeys();
      let allowedFields = [
        'status',
        'history', 
        'updatedAt',
        'currentApproverId',
        // New fields
        'bankRefNumber',
        'bankRefLink',
        // Legacy fields (for backward compatibility)
        'chequeNumber',
        'chequeImageUrl'
      ].toSet();
      return affectedKeys.hasOnly(allowedFields);
    }

    // Fund Release update validation
    // Allows checkVoucherNumber/checkVoucherLink (new) in addition to workflow fields
    function isValidFundReleaseUpdate() {
      let affectedKeys = request.resource.data.diff(resource.data).affectedKeys();
      let allowedFields = [
        'status',
        'history', 
        'updatedAt',
        'fundReleaseDate',
        // New fields
        'checkVoucherNumber',
        'checkVoucherLink',
        // COA code for expense classification
        'coaCode',
        // Legacy fields (for backward compatibility)
        'chequeNumber',
        'chequeImageUrl'
      ].toSet();
      return affectedKeys.hasOnly(allowedFields);
    }

    // =====================================================
    // MANAGER APPROVAL CHECK
    // Allows MANAGER role to approve BURFs even if permissions not configured
    // =====================================================

    function canApproveAsManager() {
      return hasPermission('procurement:burf:approve:manager');
    }

    function canApproveAsCIC() {
      return hasPermission('procurement:burf:approve:cic');
    }

    function canApprovePRF() {
      return hasPermission('procurement:prf:approve:manager');
    }

    function canApproveFinanceHeadBR() {
      return isSuperAdminOrAdmin() || hasPermission('finance:budget_request:approve:finance_head');
    }

    function canApproveCFO() {
      return isSuperAdminOrAdmin() || hasPermission('finance:budget_request:approve:cfo');
    }

    function canApproveBOD() {
      return isSuperAdminOrAdmin() || hasPermission('finance:budget_request:approve:bod');
    }

    // =====================================================
    // NOTIFICATION VALIDATION
    // Validates notification content to prevent abuse
    // =====================================================

    function isValidNotificationType(type) {
      return type in [
        'info', 'warning', 'success', 'error', 'approval', 'system', 'INFO',
        'BURF', 'PRF', 'LIQUIDATION', 'ALERT', 'REMINDER', 'AUDIT', 'PCF'
      ];
    }

    function hasValidNotificationFields(data) {
      // Require targetRoles instead of userId (userId is legacy/optional)
      // Check that targetRoles exists and is a list
      return data.keys().hasAll(['message', 'type', 'read', 'targetRoles']) &&
        data.targetRoles is list &&
        isValidStringLength(data.message, 500) &&
        isValidNotificationType(data.type) &&
        data.read is bool &&
        (!('userId' in data) || data.userId is string); // Optional userId must be string
    }


    // =====================================================
    // REQUISITIONS COLLECTION
    // =====================================================
    match /requisitions/{docId} {
      // Read: BU-based access
      allow read: if isSignedIn() && canReadRequisition(resource);

      // Create: Must be authenticated user with valid data
      // Allow PRF creation from BURF where preparer may be different from original requester
      allow create: if isSignedIn() && 
        hasRequiredRequisitionFields(request.resource.data) &&
        hasValidItems(request.resource.data.items) &&
        hasValidTextFields(request.resource.data) &&
        (
          // Standard requisition creation: user is the requester
          (request.resource.data.requesterId == request.auth.uid &&
           (request.resource.data.status == 'DRAFT' || 
            request.resource.data.status == 'BURF_PENDING_MANAGER' || 
            request.resource.data.status == 'PRF_PENDING_MANAGER'))
          ||
          // PRF created from BURF: user has permission to prepare PRF
          (request.resource.data.parentBurfId is string &&
           request.resource.data.status == 'PRF_PENDING_MANAGER' &&
           hasPermission('procurement:prf:create:from_burf'))
          ||
          // PCF Replenishment: Manager with approval permission can create PRF
          // Supports both legacy (APPROVED_FOR_PAYMENT) and new BR workflow (PENDING_FINANCE_HEAD_BR_APPROVAL)
          (request.resource.data.description.matches('.*\\[PCF_REPLENISHMENT\\].*') &&
           (request.resource.data.status == 'APPROVED_FOR_PAYMENT' ||
            request.resource.data.status == 'PENDING_FINANCE_HEAD_BR_APPROVAL') &&
           hasPermission('finance:pcf:approve'))
        );

      allow update: if isSignedIn() && (
        // SUPER ADMIN: Can do anything
        isSuperAdmin() ||

        // DRAFT Edits: Owner can edit if Draft
        (resource.data.status == 'DRAFT' && isOwner(resource)) ||

        // CANCEL: Owner or anyone with requisition:cancel permission
        (
          request.resource.data.status == 'CANCELLED' && 
          (isOwner(resource) || hasPermission('procurement:burf:cancel'))
        ) ||

        // REFILE - Owner OR PRF Preparer, from REJECTED to PENDING
        // Allows the original BURF requester OR the PRF preparer to refile
        (
          resource.data.status == 'REJECTED' &&
          (request.resource.data.status == 'BURF_PENDING_MANAGER' || request.resource.data.status == 'PRF_PENDING_MANAGER') &&
          (isOwner(resource) || isPrfPreparer(resource))
        ) ||

        // APPROVE BURF (Manager stage): Role-based OR Permission-based + same BU + field restriction
        (
          resource.data.status == 'BURF_PENDING_MANAGER' &&
          (request.resource.data.status == 'BURF_PENDING_CIC' || request.resource.data.status == 'READY_FOR_PRF') &&
          canApproveAsManager() &&
          belongsToSameBU(resource) &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE BURF (CIC stage): Role-based OR Permission-based + same BU + field restriction
        (
          resource.data.status == 'BURF_PENDING_CIC' &&
          request.resource.data.status == 'READY_FOR_PRF' &&
          canApproveAsCIC() &&
          belongsToSameBU(resource) &&
          isValidWorkflowUpdate()
        ) ||

        // BURF-to-PRF Conversion: Update BURF when creating PRF batch
        // Allows updating items/totalAmount/status when converting BURF to PRF
        // Allow BURF_PARTIALLY_PROCESSED as source (for subsequent batches) and target (when items remain)
        (
          (resource.data.status == 'READY_FOR_PRF' || resource.data.status == 'BURF_PARTIALLY_PROCESSED') &&
          (request.resource.data.status == 'READY_FOR_PRF' || 
           request.resource.data.status == 'BURF_PARTIALLY_PROCESSED' || 
           request.resource.data.status == 'BURF_COMPLETED') &&
          (belongsToSameBU(resource) || hasPermission('procurement:prf:create:from_burf')) &&
           // Restrict updates to only allow system logic changes (items, status, etc.)
          request.resource.data.diff(resource.data).affectedKeys().hasOnly(
            ['items', 'totalAmount', 'status', 'history', 'updatedAt', 'batchCounter', 'convertedItemIds']
          )
        ) ||

        // =====================================================
        // 7-STAGE PRF APPROVAL WORKFLOW
        // =====================================================

        // APPROVE PRF Stage 1: Manager → GM PRF (if >= 50k) or Finance Head (if < 50k)
        (
          resource.data.status == 'PRF_PENDING_MANAGER' &&
          (request.resource.data.status == 'PENDING_GM_PRF_APPROVAL' ||
           request.resource.data.status == 'PENDING_FINANCE_HEAD_BR_APPROVAL') &&
          canApprovePRF() &&
          belongsToSameBU(resource) &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 2: GM PRF → Finance Head BR
        (
          resource.data.status == 'PENDING_GM_PRF_APPROVAL' &&
          request.resource.data.status == 'PENDING_FINANCE_HEAD_BR_APPROVAL' &&
          canApprovePRF() &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 3: Finance Head BR → GM Budget
        (
          resource.data.status == 'PENDING_FINANCE_HEAD_BR_APPROVAL' &&
          request.resource.data.status == 'PENDING_GM_BR_APPROVAL' &&
          canApproveFinanceHeadBR() &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 4: GM Budget → BOD Approval
        (
          resource.data.status == 'PENDING_GM_BR_APPROVAL' &&
          request.resource.data.status == 'PENDING_BOD_APPROVAL' &&
          canApprovePRF() &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 5: BOD Approval → Check Preparation
        (
          resource.data.status == 'PENDING_BOD_APPROVAL' &&
          request.resource.data.status == 'FOR_CHECK_PREPARATION' &&
          canApproveBOD() &&
          isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 6: Check Preparation → Check Auth BOD (Finance uploads check)
        (
          resource.data.status == 'FOR_CHECK_PREPARATION' &&
          request.resource.data.status == 'PENDING_CHECK_AUTH_BOD' &&
          hasPermission('finance:cheque:upload') &&
          isValidCheckPrepUpdate()
        ) ||

        // APPROVE PRF Stage 7: Check Auth BOD → Fund Release
        (
          resource.data.status == 'PENDING_CHECK_AUTH_BOD' &&
          request.resource.data.status == 'FOR_FUND_RELEASE' &&
          (canApproveBOD() || hasPermission('finance:cheque:authorize') || hasRole('BOARD_OF_DIRECTOR') || hasRole('ES'))
          // TEMPORARY WORKAROUND: Bypass isValidWorkflowUpdate()
          // && isValidWorkflowUpdate()
        ) ||

        // APPROVE PRF Stage 8: For Fund Release → Funds Released (Finance)
        (
          resource.data.status == 'FOR_FUND_RELEASE' &&
          request.resource.data.status == 'FUNDS_RELEASED' &&
          hasPermission('finance:cheque:release') &&
          isValidFundReleaseUpdate()
        ) ||

        // PCF Replenishment: Fund Release → Audited Cleared (no liquidation needed)
        // PCF Replenishments have linkedPcfId and skip the liquidation step entirely
        (
          resource.data.status == 'FOR_FUND_RELEASE' &&
          request.resource.data.status == 'AUDITED_CLEARED' &&
          hasPermission('finance:cheque:release') &&
          isValidFundReleaseUpdate()
        ) ||

        // LEGACY: CFO → BOD (for existing data in old workflow)
        (
          resource.data.status == 'PENDING_CFO_APPROVAL' &&
          request.resource.data.status == 'PENDING_BOD_APPROVAL' &&
          canApproveCFO() &&
          isValidWorkflowUpdate()
        ) ||

        // LEGACY: APPROVE PRF (old workflow - kept for backward compatibility)
        (
          resource.data.status == 'PRF_PENDING_MANAGER' &&
          request.resource.data.status == 'APPROVED_FOR_PAYMENT' &&
          canApprovePRF() &&
          belongsToSameBU(resource) &&
          isValidWorkflowUpdate()
        ) ||

        // REJECT: Any approver role OR permission + same BU + field restriction
        // Includes all 8-stage workflow approvers
        (
          request.resource.data.status == 'REJECTED' &&
          (canApproveAsManager() || canApproveAsCIC() || canApprovePRF() || 
           canApproveFinanceHeadBR() || canApproveCFO() || canApproveBOD() ||
           hasPermission('finance:cheque:upload')) &&
          belongsToSameBU(resource) &&
          isValidWorkflowUpdate()
        ) ||

        // Finance: Release Funds - Permission-based
        (
          request.resource.data.status == 'FUNDS_RELEASED' &&
          hasPermission('finance:cheque:release')
        ) ||

        // Liquidation: File - Permission-based
        (
          resource.data.status == 'FUNDS_RELEASED' &&
          request.resource.data.status == 'LIQUIDATION_FILED' &&
          (hasPermission('finance:liquidation:create:all') || 
           (hasPermission('finance:liquidation:create:own') && isOwner(resource)))
        ) ||

        // Liquidation: Refile after rejection - Permission-based
        (
          resource.data.status == 'LIQUIDATION_REJECTED' &&
          request.resource.data.status == 'LIQUIDATION_FILED' &&
          (hasPermission('finance:liquidation:create:all') || 
           (hasPermission('finance:liquidation:create:own') && isOwner(resource)))
        ) ||

        // Liquidation: Audit - Permission-based
        (
          resource.data.status == 'LIQUIDATION_FILED' &&
          (request.resource.data.status == 'AUDITED_CLEARED' || request.resource.data.status == 'LIQUIDATION_REJECTED') &&
          hasPermission('finance:liquidation:audit')
        )
      );
    }

    // =====================================================
    // USERS COLLECTION
    // =====================================================
    match /users/{userId} {
      allow read: if isSignedIn();

      // Self-update or admin:manage:users permission
      allow update: if isSignedIn() && 
        (request.auth.uid == userId || hasPermission('admin:user:edit'));

      // Create: Allow self-registration OR admin:manage:users permission
      // Self-registration requires:
      //   1. Creating document for own UID
      //   2. Status must be PENDING_APPROVAL (prevents users from granting themselves immediate access)
      //   3. Email must match the authenticated user's email
      // Note: Self-registration check MUST come first because hasPermission() will error
      // if the user document doesn't exist yet (which is the case during self-registration)
      allow create: if isSignedIn() && (
        (
          request.auth.uid == userId &&
          request.resource.data.status == 'PENDING_APPROVAL' &&
          request.resource.data.email == request.auth.token.email
        ) ||
        hasPermission('admin:user:edit')
      );

      // Delete requires admin:manage:users permission
      allow delete: if isSignedIn() && hasPermission('admin:user:edit');
    }

    // =====================================================
    // BUSINESSES COLLECTION
    // =====================================================
    match /businesses/{id} {
      allow read: if isSignedIn();

      // Permission-based business management
      allow create, update, delete: if isSignedIn() && hasPermission('admin:business:edit');
    }

    // =====================================================
    // NOTIFICATIONS COLLECTION
    // FIX BUG 14: Locked down with strict validation
    // - User can only read/update/delete their own notifications
    // - Creates require valid structure and content validation
    // =====================================================
    match /notifications/{id} {
      // Read: Only own notifications
      // Read: Users can read if they are the target (by ID) or their role is targeted
      allow read: if isSignedIn() && (request.auth.uid in resource.data.targetRoles);

      // Create: Any authenticated user can create notifications for any user
      allow create: if isSignedIn() && 
        hasValidNotificationFields(request.resource.data);

      // Update: Only own notifications, only allow marking as read
      allow update: if isSignedIn() && 
        (resource.data.userId == request.auth.uid || 
         request.auth.uid in resource.data.targetRoles) &&
        request.resource.data.diff(resource.data).affectedKeys().hasOnly(['read', 'updatedAt']);

      // Delete: Only own notifications (check both legacy userId and targetRoles)
      allow delete: if isSignedIn() && 
        (resource.data.userId == request.auth.uid || 
         request.auth.uid in resource.data.targetRoles);
    }

    // =====================================================
    // SUPPLIERS COLLECTION
    // =====================================================
    match /suppliers/{id} {
      allow read: if isSignedIn();

      // Permission-based supplier management
      allow create: if isSignedIn() && hasPermission('master_data:supplier:create');
      allow update: if isSignedIn() && hasPermission('master_data:supplier:edit');
      allow delete: if isSignedIn() && hasPermission('master_data:supplier:delete');
    }

    // =====================================================
    // CONFIG COLLECTION
    // =====================================================
    match /config/{document} {
      allow read: if isSignedIn();

      // Only admins or users with specific permission can update config documents
      allow write: if isSignedIn() && (isSuperAdmin() || hasPermission('admin:permission:edit'));
    }

    // =====================================================
    // COUNTERS COLLECTION (Issue #6 - Secured)
    // =====================================================
    match /counters/{counterId} {
      allow read: if isSignedIn();

      // Allow creation of new counters with required fields
      // FIX BUG 13: First counter must start at exactly 1 (not 0)
      // This ensures IDs like PRF-0001 instead of PRF-0000
      allow create: if isSignedIn() && 
        request.resource.data.keys().hasAll(['value', 'prefix']) &&
        request.resource.data.value is int &&
        request.resource.data.value == 1; // First value MUST be 1

      // Only allow incrementing the value (new value must be greater than old)
      // FIX: Removed prefix check since update() doesn't include unchanged fields
      // The prefix is protected because it's not in the updateMask
      allow update: if isSignedIn() && 
        request.resource.data.value is int &&
        request.resource.data.value > resource.data.value;

      // Prevent deletion
      allow delete: if false;
    }

    // =====================================================
    // UOM COLLECTION
    // =====================================================
    match /uom/{uomId} {
      allow read: if isSignedIn();

      // Permission-based UOM management
      allow create, update, delete: if isSignedIn() && hasPermission('inventory:uom:edit');
    }

    // =====================================================
    // PCF LIQUIDATIONS COLLECTION
    // Petty Cash Fund liquidation records with approval workflow
    // =====================================================
    match /pcf_liquidations/{liquidationId} {
      // Users can read their own liquidations, or if they have PCF approval/view permissions
      allow read: if isSignedIn() && (
        resource.data.userId == request.auth.uid ||
        isSuperAdminOrAdmin() ||
        hasPermission('finance:pcf:approve') ||
        hasPermission('finance:pcf:view:all') ||
        hasPermission('pcf:view') ||
        hasPermission('finance:pcf:audit')
      );

      // Users can create liquidations for themselves (DRAFT, PENDING_APPROVAL, or AUDIT_REVIEW)
      allow create: if isSignedIn() && 
        request.resource.data.userId == request.auth.uid &&
        (request.resource.data.status == 'DRAFT' || request.resource.data.status == 'PENDING_APPROVAL' || request.resource.data.status == 'AUDIT_REVIEW');

      // Owner can update DRAFT liquidations or submit for approval
      // Owner can refile REJECTED liquidations
      // Managers can approve/reject PENDING_APPROVAL liquidations
      // Finance can mark APPROVED_WAITING_RELEASE as REPLENISHED when funds are released
      allow update: if isSignedIn() && (
        // Owner updating own DRAFT
        (resource.data.userId == request.auth.uid && resource.data.status == 'DRAFT') ||
        // Owner submitting DRAFT for approval
        (resource.data.userId == request.auth.uid && 
         resource.data.status == 'DRAFT' && 
         (request.resource.data.status == 'PENDING_APPROVAL' || request.resource.data.status == 'AUDIT_REVIEW')) ||
        // Owner refiling REJECTED for approval
        (resource.data.userId == request.auth.uid && 
         resource.data.status == 'REJECTED' && 
         (request.resource.data.status == 'PENDING_APPROVAL' || request.resource.data.status == 'AUDIT_REVIEW')) ||
        // Manager/Approver approving/rejecting PCF
        (hasPermission('finance:pcf:approve') && 
         resource.data.status == 'PENDING_APPROVAL' &&
         (request.resource.data.status == 'APPROVED' || 
          request.resource.data.status == 'APPROVED_WAITING_RELEASE' || 
          request.resource.data.status == 'REJECTED')) ||
        // PCF CANCEL: Admin, Owner, or anyone with pcf:cancel permission
        ((isSuperAdmin() || hasPermission('finance:pcf:cancel')) && 
         (resource.data.status == 'PENDING_APPROVAL' || resource.data.status == 'APPROVED_WAITING_RELEASE') &&
         request.resource.data.status == 'CANCELLED') ||
        // Finance marking as REPLENISHED when releasing funds
        // Allow from both APPROVED and APPROVED_WAITING_RELEASE statuses
        // PCF Replenishment PRFs update the linked PCF to REPLENISHED during fund release
        (hasPermission('finance:cheque:release') && 
         (resource.data.status == 'APPROVED_WAITING_RELEASE' || resource.data.status == 'APPROVED') && 
         request.resource.data.status == 'REPLENISHED') ||
        // SuperAdmin or audit reviewer can update PCF liquidations
        isSuperAdminOrAdmin() ||
        hasPermission('finance:pcf:audit')
      );

      // No deletion allowed - audit trail required
      allow delete: if false;
    }
    // =====================================================
    // CHART OF ACCOUNTS COLLECTION
    // Stores COA codes for expense classification
    // =====================================================
    match /chart_of_accounts/{accountId} {
      // All authenticated users can read COA for dropdowns
      allow read: if isSignedIn();

      // Only admins can create/update/delete COA entries
      allow create, update, delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // SETTINGS COLLECTION
    // Stores system configuration like PCF settings
    // =====================================================
    match /settings/{document} {
      // All authenticated users can read settings
      allow read: if isSignedIn();

      // Only admins can write settings
      allow write: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // INVENTORY ITEMS COLLECTION
    // Multi-tenant inventory items scoped by businessUnitId
    // =====================================================
    match /inventory_items/{itemId} {
      allow read: if isSignedIn() && (
        isSuperAdminOrAdmin() ||
        hasPermission('inventory:item:view:all') ||
        (hasPermission('inventory:item:view:bu') && belongsToSameBU(resource)) ||
        // Fallback for backwards compatibility if no explicit permission
        (!hasPermission('inventory:item:view:all') && !hasPermission('inventory:item:view:bu') && belongsToSameBU(resource))
      );

      allow create: if isSignedIn() && (hasPermission('inventory:item:create') || hasPermission('inventory:item:edit'));

      allow update: if isSignedIn() && (
        hasPermission('inventory:item:edit') ||
        (hasPermission('ui:module_access:view:pos') && request.resource.data.diff(resource.data).affectedKeys().hasOnly(['currentStock', 'theoreticalStock', 'updatedAt'])) ||
        hasPermission('pos:import:delete') ||
        hasPermission('pos:import:create')
      );

      allow delete: if isSignedIn() && (hasPermission('inventory:item:delete') || isSuperAdminOrAdmin());
    }

    // =====================================================
    // STOCK COUNTS COLLECTION
    // Session-based stock counting records
    // =====================================================
    match /stock_counts/{countId} {
      allow read: if isSignedIn() && (
        isSuperAdminOrAdmin() ||
        hasPermission('inventory:stock_take:view:all') ||
        (hasPermission('inventory:stock_take:view:bu') && belongsToSameBU(resource)) ||
        (hasPermission('inventory:stock_take:view:own') && resource.data.performedBy == request.auth.uid) ||
        (!hasPermission('inventory:stock_take:view:all') && !hasPermission('inventory:stock_take:view:bu') && !hasPermission('inventory:stock_take:view:own') && belongsToSameBU(resource))
      );

      allow create: if isSignedIn() && (hasPermission('inventory:stock_take:create') || true); // temporary fallback

      allow update: if isSignedIn() && (
        hasPermission('inventory:stock_take:edit') ||
        hasPermission('inventory:stock_take:approve_adjustment') ||
        hasPermission('inventory:stock_take:freeze') ||
        resource.data.performedBy == request.auth.uid ||
        isSuperAdminOrAdmin()
      );

      allow delete: if isSignedIn() && (hasPermission('inventory:stock_take:delete') || isSuperAdminOrAdmin());
    }

    // =====================================================
    // WASTAGE RECORDS COLLECTION
    // Multi-tenant wastage audit logs
    // =====================================================
    match /wastage_records/{wastageId} {
      allow read: if isSignedIn() && (
        isSuperAdminOrAdmin() ||
        hasPermission('inventory:wastage:view:all') ||
        (hasPermission('inventory:wastage:view:bu') && belongsToSameBU(resource)) ||
        (hasPermission('inventory:wastage:view:own') && resource.data.performedBy == request.auth.uid) ||
        (!hasPermission('inventory:wastage:view:all') && !hasPermission('inventory:wastage:view:bu') && !hasPermission('inventory:wastage:view:own') && belongsToSameBU(resource))
      );

      allow create: if isSignedIn() && (hasPermission('inventory:wastage:create') || true);

      allow update: if isSignedIn() && (hasPermission('inventory:wastage:edit') || isSuperAdminOrAdmin());
      allow delete: if isSignedIn() && (hasPermission('inventory:wastage:delete') || isSuperAdminOrAdmin());
    }

    // =====================================================
    // STOCKTAKE AUDIT LOGS COLLECTION
    // Immutable per-item before/after log written on session submit
    // =====================================================
    match /stocktake_audit_logs/{logId} {
      // Any authenticated user can read (BU scoping enforced by service-level where clause)
      allow read: if isSignedIn();

      // Any authenticated user can create (written by submitSession)
      allow create: if isSignedIn();

      // Immutable - no edits or deletes allowed
      allow update, delete: if false;
    }



    // =====================================================
    // MENU ITEMS COLLECTION (Menu Engineering)
    // Multi-tenant menu items with recipes scoped by businessUnitId
    // =====================================================
    match /menu_items/{itemId} {
      // Read: Any authenticated user (BU scoping enforced by app-level where clause)
      allow read: if isSignedIn();

      // Create/Update: Any authenticated user can manage menu items
      // Delete: Admin only (to prevent accidental data loss)
      allow create, update: if isSignedIn();
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // PRODUCTION RECIPES COLLECTION (Menu Engineering)
    // Multi-tenant recipes including yield and ingredients
    // =====================================================
    match /productionRecipes/{recipeId} {
      // Read: Any authenticated user (BU scoping enforced by app-level where clause)
      allow read: if isSignedIn();

      // Create/Update: Any authenticated user can manage recipes
      allow create, update: if isSignedIn();

      // Delete: Admin only
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // BLACK BOOK RECIPES COLLECTION (Menu Engineering)
    // Multi-tenant operational recipes scoped by businessUnitId
    // =====================================================
    match /blackBookRecipes/{recipeId} {
      // Read: Any authenticated user (BU scoping enforced by app-level where clause)
      allow read: if isSignedIn();

      // Create/Update: Any authenticated user can manage black book recipes
      allow create, update: if isSignedIn();

      // Delete: Admin only
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // BUDGETS COLLECTION
    // Budget limits per Business Unit + COA + Fiscal Year
    // Read: All authenticated users can view budget limits
    // Write: DENIED - All writes must go through setBudgetLimit Cloud Function
    // This ensures RBAC (only FINANCE_HEAD can modify) and data validation
    // =====================================================
    match /budgets/{budgetId} {
      // Any authenticated user can read budgets (to see their limits)
      allow read: if isSignedIn();

      // Create: Only FINANCE_HEAD or SUPER_ADMIN can create budget limits
      allow create: if isSignedIn() && (
        isSuperAdmin() || 
        hasPermission('master_data:budget:edit')
      );

      // Update: Authenticated users can update reserved field (for reservations during approval)
      // Full budget limit updates require FINANCE_HEAD permission
      allow update: if isSignedIn() && (
        isSuperAdmin() || 
        hasPermission('master_data:budget:edit') ||
        // Allow any authenticated user to update reserved/updatedAt fields only (for reservations)
        request.resource.data.diff(resource.data).affectedKeys().hasOnly(['reserved', 'updatedAt'])
      );

      // Delete requires admin
      allow delete: if isSignedIn() && isSuperAdmin();
    }

    // =====================================================
    // BUDGET RESERVATIONS COLLECTION
    // Tracks budget reservations created during PRF approval process
    // Released when PRF is rejected/cancelled, committed when funds are released
    // =====================================================
    match /budgetReservations/{reservationId} {
      // Any authenticated user can read reservations
      allow read: if isSignedIn();

      // Create: Any authenticated user can create reservations 
      // (created during PRF approval stages)
      allow create: if isSignedIn();

      // Update: Any authenticated user can update reservations
      // (status changes: RESERVED -> RELEASED/COMMITTED)
      allow update: if isSignedIn();

      // Delete: Only admins can delete reservations
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // TRANSACTIONS COLLECTION
    // Financial transactions that affect budgets
    // Read: Authenticated users (for reporting)
    // Write: DENIED - All writes must go through postTransaction Cloud Function
    // This ensures budget validation before any transaction is recorded
    // =====================================================
    match /transactions/{transactionId} {
      // Authenticated users can read transactions for reporting
      allow read: if isSignedIn();

      // All writes MUST go through the postTransaction Cloud Function
      // This ensures budget limits are validated atomically
      allow write: if false;
    }


    // =====================================================
    // BANK RECONCILIATION STATEMENTS COLLECTION
    // Stores uploaded bank statements for reconciliation
    // =====================================================
    match /bankReconStatements/{statementId} {
      // Read: Any authenticated user
      allow read: if isSignedIn();

      // Create: Any authenticated user can upload bank statements
      allow create: if isSignedIn();

      // Update: Any authenticated user (for enrichment/matching)
      allow update: if isSignedIn();

      // Delete: Any authenticated user can delete their uploads
      allow delete: if isSignedIn();

      // Sub-collection: sheetData (individual sheet rows)
      match /sheetData/{sheetId} {
        allow read: if isSignedIn();
        allow create: if isSignedIn();
        allow update: if isSignedIn();
        allow delete: if isSignedIn();
      }
    }

    // =====================================================
    // POS ORDERS COLLECTION
    // Point-of-sale orders
    // =====================================================
    match /pos_orders/{orderId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      allow update: if isSignedIn();
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // POS TABLES COLLECTION
    // Table layouts for POS
    // =====================================================
    match /pos_tables/{tableId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      allow update: if isSignedIn();
      allow delete: if isSignedIn();
    }

    // =====================================================
    // POS RUNNING BILLS COLLECTION
    // Dine-in running bills attached to tables
    // =====================================================
    match /pos_running_bills/{billId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      allow update: if isSignedIn();
      allow delete: if isSignedIn(); // Allow delete for testing/reset if needed
    }

    // =====================================================
    // POS SALES COLLECTION
    // Imported POS sales records linked to inventory items
    // =====================================================
    match /pos_sales/{saleId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Allow delete for rollback
      allow delete: if isSignedIn() && (isSuperAdminOrAdmin() || hasPermission('pos:import:delete'));
      allow update: if false;
    }

    // =====================================================
    // POS SALES BATCHES COLLECTION
    // Metadata for each POS import batch (idempotency)
    // =====================================================
    match /pos_sales_batches/{batchId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Allow delete for rollback
      allow delete: if isSignedIn() && (isSuperAdminOrAdmin() || hasPermission('pos:import:delete'));
      allow update: if false;
    }

    // =====================================================
    // EVENT SALES COLLECTION
    // Imported event sales records with BOM-exploded items
    // =====================================================
    match /event_sales/{saleId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Only admins can delete for rollback
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
      allow update: if false;
    }

    // =====================================================
    // PRODUCTION LOGS COLLECTION
    // Logs for auto-production during POS imports
    // =====================================================
    match /production_logs/{logId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Allow delete for rollback
      allow delete: if isSignedIn() && (isSuperAdminOrAdmin() || hasPermission('pos:import:delete'));
      allow update: if false;
    }

    // =====================================================
    // EVENT IMPORT BATCHES COLLECTION
    // Metadata for each event import batch (idempotency/history)
    // =====================================================
    match /event_import_batches/{batchId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Only admins can delete for rollback
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
      allow update: if false;
    }

    // =====================================================
    // EVENT PACKAGE TEMPLATES COLLECTION
    // Reusable event package templates
    // =====================================================
    match /event_package_templates/{templateId} {
      allow read: if isSignedIn();
      allow create, update: if isSignedIn();
      allow delete: if isSignedIn() && isSuperAdminOrAdmin();
    }

    // =====================================================
    // INVENTORY AGGREGATES COLLECTION
    // Multi-tenant aggregate data for inventory dashboard
    // =====================================================
    match /inventory_aggregates/{aggId} {
      allow read: if isSignedIn();
      allow write: if false;
    }

    // =====================================================
    // STOCK TRANSACTIONS COLLECTION
    // Immutable audit trail of all inventory movements
    // =====================================================
    match /stock_transactions/{txId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // Allow deletion for POS import rollback
      allow delete: if isSignedIn() && (isSuperAdminOrAdmin() || hasPermission('pos:import:delete'));
      // No updates — immutable audit trail
      allow update: if false;
    }

    // =====================================================
    // RECONCILIATION HISTORY COLLECTION
    // Immutable snapshots of inventory reconciliation records
    // =====================================================
    match /recon_history/{recordId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // No updates or deletes — immutable snapshot record
      allow update, delete: if false;
    }

    // =====================================================
    // WASTAGE RECORDS COLLECTION
    // Immutable records of inventory wastage events
    // =====================================================
    match /wastage_records/{recordId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      // No updates or deletes — immutable wastage audit trail
      allow update, delete: if false;
    }

    // =====================================================
    // GOODS RECEIVING LOGS COLLECTION
    // Immutable audit log of all goods receiving sessions
    // Records who uploaded/scanned, what was received, and linked PRF
    // =====================================================
    match /goods_receiving_logs/{logId} {
      allow read: if isSignedIn() && (
        isSuperAdminOrAdmin() ||
        hasPermission('inventory:receiving:view:all') ||
        (hasPermission('inventory:receiving:view:bu') && belongsToSameBU(resource)) ||
        (hasPermission('inventory:receiving:view:own') && resource.data.performedBy == request.auth.uid) ||
        (!hasPermission('inventory:receiving:view:all') && !hasPermission('inventory:receiving:view:bu') && !hasPermission('inventory:receiving:view:own'))
      );
      allow create: if isSignedIn() && (hasPermission('inventory:receiving:create') || true);
      allow update: if isSignedIn() && (hasPermission('inventory:receiving:edit') || hasPermission('inventory:receiving:reject') || isSuperAdminOrAdmin());
      allow delete: if isSignedIn() && (hasPermission('inventory:receiving:delete') || isSuperAdminOrAdmin());
    }

    // =====================================================
    // SYSTEM ACTIVITY LOGS COLLECTION
    // Global audit log for all modules (Finance, Inventory,
    // POS, Wastage, Reconciliation, Goods Receiving, etc.)
    // =====================================================
    match /system_activity_logs/{logId} {
      // Read: SuperAdmin only (scoped filtering happens in app)
      allow read: if isSignedIn() && isSuperAdmin();
      // Create: Any authenticated user — all modules write here
      allow create: if isSignedIn();
      // No updates or deletes — immutable audit trail
      allow update, delete: if false;
    }

    // =====================================================
    // INVENTORY INVESTIGATIONS COLLECTION
    // Case management for flagged inventory variances
    // Client-side query already scopes by businessId
    // =====================================================
    match /inventory_investigations/{caseId} {
      allow read: if isSignedIn();
      allow create: if isSignedIn();
      allow update: if isSignedIn();
      // Investigations are preserved as audit records — no deletion
      allow delete: if false;
    }
  }
}
